using System;
using System.IO;
using Abbey.Beast;
using Abbey.CameraRig;
using Abbey.Core;
using Abbey.Debugging;
using Abbey.Hero;
using Abbey.Light;
using Abbey.Nightmares;
using Abbey.Villagers;
using UnityEditor;
using UnityEditor.SceneManagement;
using UnityEngine;

namespace Abbey.EditorTools
{
    /// <summary>
    /// Builds and saves the Prototype 0.1 greybox scene entirely from code
    /// (AGENTS.md: scenes are generated by editor bootstrap code and are never the
    /// source of truth for logic). Layout follows docs/VERTICAL_SLICE_SPEC.md §2:
    /// shipwreck beach SW, ruined abbey hill NE (bell tower + chained hound), camp
    /// center (campfire + storage), forest edge NW, a stream. Where a generated
    /// Blender GLB is already imported under Assets/Generated/BlenderAssets it is
    /// instantiated; otherwise the builder degrades to primitives — the menu item
    /// never fails hard on missing art.
    /// </summary>
    public static class PrototypeSceneBuilder
    {
        public const string ScenePath = "Assets/_Game/Scenes/Prototype01.unity";
        public const string GeneratedAssetFolder = "Assets/Generated/BlenderAssets";

        // Landmark positions (map layout, not balance — the map is authored here).
        static readonly Vector3 CampCenter = Vector3.zero;
        static readonly Vector3 BeachCenter = new Vector3(-30f, 0f, -30f);
        static readonly Vector3 AbbeyHillCenter = new Vector3(28f, 0f, 28f);
        static readonly Vector3 ForestEdgeCenter = new Vector3(-28f, 0f, 28f);
        static readonly Vector3 FarVillagerPost = new Vector3(-30f, 0f, 30f);

        [MenuItem("Tools/Abbey/Build Prototype Scene")]
        public static void BuildPrototypeScene()
        {
            var scene = EditorSceneManager.NewScene(NewSceneSetup.EmptyScene, NewSceneMode.Single);
            PopulateScene();

            try
            {
                string dir = Path.GetDirectoryName(Path.GetFullPath(
                    Path.Combine(Application.dataPath, "..", ScenePath)));
                if (!string.IsNullOrEmpty(dir))
                {
                    Directory.CreateDirectory(dir);
                }
                if (EditorSceneManager.SaveScene(scene, ScenePath))
                {
                    Debug.Log($"[Abbey] Prototype greybox scene built and saved to {ScenePath}.");
                }
                else
                {
                    Debug.LogWarning("[Abbey] Scene populated but SaveScene failed; " +
                                     "the open scene is still fully usable (press Play).");
                }
            }
            catch (Exception e)
            {
                Debug.LogWarning($"[Abbey] Scene populated but saving threw: {e.Message}. " +
                                 "The open scene is still fully usable (press Play).");
            }
        }

        /// <summary>Creates every greybox world object in the active scene.</summary>
        public static void PopulateScene()
        {
            var config = PrototypeConfig.LoadOrDefault();

            BuildGroundAndSun();
            BuildSimulationCore(config);
            var hero = BuildHero();
            BuildCamera(config, hero.transform);
            BuildCamp(config);
            BuildBeach();
            BuildAbbeyHill(config);
            BuildForestEdgeAndStream();
            BuildVillagers();
            BuildWorkAssignments();
        }

        // ------------------------------------------------------------------
        // World chunks
        // ------------------------------------------------------------------

        static void BuildGroundAndSun()
        {
            // Coastal meadow placeholder, 100x100 units.
            var ground = GameObject.CreatePrimitive(PrimitiveType.Plane);
            ground.name = "Ground";
            ground.transform.localScale = new Vector3(10f, 1f, 10f);

            // Fixed sun matching the camera-relative light rule in ART_BIBLE.md.
            var sunGO = new GameObject("Sun");
            var sun = sunGO.AddComponent<UnityEngine.Light>();
            sun.type = LightType.Directional;
            sunGO.transform.rotation = Quaternion.Euler(50f, IsoCameraController.Yaw - 30f, 0f);
        }

        static void BuildSimulationCore(PrototypeConfig config)
        {
            var clockGO = new GameObject("GameClock");
            clockGO.AddComponent<GameClock>();

            // Villagers register with the static DuskRecallSystem in OnEnable —
            // no scene object needed for it.

            var directorGO = new GameObject("NightmareDirector");
            directorGO.transform.position = CampCenter; // spawn ring measured from camp
            directorGO.AddComponent<NightmareDirector>();

            var debugGO = new GameObject("DebugOverlay");
            debugGO.AddComponent<DebugOverlay>();
            debugGO.AddComponent<LightZoneGizmos>();
        }

        static GameObject BuildHero()
        {
            var hero = GameObject.CreatePrimitive(PrimitiveType.Capsule);
            hero.name = "Bellkeeper";
            hero.transform.position = new Vector3(2f, 1f, -2f);
            var controller = hero.AddComponent<BellkeeperController>();
            controller.useDirectInput = true;
            hero.AddComponent<BellkeeperInputBindings>();
            return hero;
        }

        static void BuildCamera(PrototypeConfig config, Transform followTarget)
        {
            var camGO = new GameObject("IsoCamera");
            camGO.tag = "MainCamera";
            var cam = camGO.AddComponent<Camera>();
            cam.orthographic = true;
            cam.orthographicSize = config.cameraDefaultOrthoSize;
            camGO.transform.rotation = Quaternion.Euler(
                IsoCameraController.Pitch, IsoCameraController.Yaw, 0f);
            var rig = camGO.AddComponent<IsoCameraController>();
            rig.SetWorldBounds(new Vector2(-50f, -50f), new Vector2(50f, 50f));
            rig.FocusOn(CampCenter);
            rig.SetFollowTarget(followTarget);
        }

        static void BuildCamp(PrototypeConfig config)
        {
            // Campfire: the first light zone. GLB when imported, cylinder otherwise.
            var campfire = InstantiateGenerated("campfire_t1", CampCenter, "Campfire",
                PrimitiveType.Cylinder, new Vector3(0.8f, 0.25f, 0.8f), 0.25f);
            var fireLight = campfire.AddComponent<LightSource>();
            fireLight.radius = config.campfireRadius;
            fireLight.strength = config.campfireStrength;
            fireLight.fuelSeconds = config.defaultFuelSeconds;
            fireLight.fuelConsumptionPerSecond = config.fuelConsumptionPerSecond;

            InstantiateGenerated("storage_pile_t1", new Vector3(3f, 0f, 3f), "StoragePile",
                PrimitiveType.Cube, new Vector3(1.2f, 0.6f, 1.2f), 0.3f);
            InstantiateGenerated("shelter_t1", new Vector3(-4f, 0f, 2f), "Shelter_A",
                PrimitiveType.Cube, new Vector3(2f, 1.5f, 2f), 0.75f);
            InstantiateGenerated("shelter_t1", new Vector3(-2f, 0f, 5f), "Shelter_B",
                PrimitiveType.Cube, new Vector3(2f, 1.5f, 2f), 0.75f);

            // Lantern post on the camp's dark side, toward the abbey path.
            var lantern = InstantiateGenerated("lantern_post_t1", new Vector3(10f, 0f, 6f),
                "LanternPost", PrimitiveType.Cube, new Vector3(0.3f, 2f, 0.3f), 1f);
            var lanternLight = lantern.AddComponent<LightSource>();
            lanternLight.radius = config.lanternRadius;
            lanternLight.strength = config.lanternStrength;
            lanternLight.fuelSeconds = config.defaultFuelSeconds;
            lanternLight.fuelConsumptionPerSecond = config.fuelConsumptionPerSecond;
        }

        static void BuildBeach()
        {
            InstantiateGenerated("shipwreck_hull", BeachCenter, "ShipwreckHull",
                PrimitiveType.Cube, new Vector3(8f, 2.5f, 3f), 1.25f);
            InstantiateGenerated("shipwreck_crate_closed", BeachCenter + new Vector3(4f, 0f, 2f),
                "WreckCrate_A", PrimitiveType.Cube, new Vector3(1f, 1f, 1f), 0.5f);
            InstantiateGenerated("shipwreck_crate_closed", BeachCenter + new Vector3(5.5f, 0f, 0.5f),
                "WreckCrate_B", PrimitiveType.Cube, new Vector3(1f, 1f, 1f), 0.5f);
            InstantiateGenerated("shipwreck_barrel", BeachCenter + new Vector3(2f, 0f, 4f),
                "WreckBarrel", PrimitiveType.Cylinder, new Vector3(0.5f, 0.5f, 0.5f), 0.5f);
        }

        static void BuildAbbeyHill(PrototypeConfig config)
        {
            // Low greybox hill so the abbey reads as "up".
            var hill = GameObject.CreatePrimitive(PrimitiveType.Cylinder);
            hill.name = "AbbeyHill";
            hill.transform.position = AbbeyHillCenter + new Vector3(0f, 0.25f, 0f);
            hill.transform.localScale = new Vector3(12f, 0.25f, 12f);
            float hillTop = 0.5f;

            var towerPos = AbbeyHillCenter + new Vector3(0f, hillTop, 0f);
            InstantiateGenerated("bell_tower_ruined", towerPos, "BellTower",
                PrimitiveType.Cube, new Vector3(3f, 6f, 3f), 3f);
            InstantiateGenerated("abbey_wall_broken", towerPos + new Vector3(-4f, 0f, 1f),
                "AbbeyWall_A", PrimitiveType.Cube, new Vector3(4f, 1.5f, 0.5f), 0.75f);
            InstantiateGenerated("abbey_wall_broken", towerPos + new Vector3(1f, 0f, -4f),
                "AbbeyWall_B", PrimitiveType.Cube, new Vector3(0.5f, 1.5f, 4f), 0.75f);

            // Sacred abbey flame: win/loss anchor and the hound's home light.
            var flameGO = new GameObject("AbbeyFlame");
            flameGO.transform.position = towerPos + new Vector3(1.5f, 0f, 1.5f);
            var flame = flameGO.AddComponent<LightSource>();
            flame.radius = config.sacredFlameRadius;
            flame.strength = config.sacredFlameStrength;
            flame.sacred = true;
            flame.fuelSeconds = -1f; // 0.1: the sacred flame does not burn out

            // The chained Black Hound at the tower base.
            var chainPos = towerPos + new Vector3(2f, 0f, -1.5f);
            InstantiateGenerated("hound_chain", chainPos, "HoundChain",
                PrimitiveType.Cylinder, new Vector3(0.3f, 0.1f, 0.3f), 0.1f);
            var hound = InstantiateGenerated("black_hound_lowpoly",
                chainPos + new Vector3(0.8f, 0f, 0f), "BlackHound",
                PrimitiveType.Capsule, new Vector3(1.2f, 0.9f, 1.2f), 0.9f);
            hound.AddComponent<HoundController>();
        }

        static void BuildForestEdgeAndStream()
        {
            for (int i = 0; i < 5; i++)
            {
                var offset = new Vector3((i % 3) * 4f - 4f, 0f, (i / 3) * 5f);
                InstantiateGenerated("forest_tree_01", ForestEdgeCenter + offset,
                    $"ForestTree_{i}", PrimitiveType.Cylinder,
                    new Vector3(0.5f, 3f, 0.5f), 3f);
            }
            InstantiateGenerated("rock_cluster_01", ForestEdgeCenter + new Vector3(6f, 0f, -3f),
                "RockCluster", PrimitiveType.Sphere, new Vector3(1.5f, 1f, 1.5f), 0.4f);

            // Stream: a flat blue strip running along the forest edge toward the sea.
            var stream = GameObject.CreatePrimitive(PrimitiveType.Cube);
            stream.name = "Stream";
            stream.transform.position = new Vector3(-15f, 0.02f, 18f);
            stream.transform.localScale = new Vector3(45f, 0.05f, 2.5f);
            stream.transform.rotation = Quaternion.Euler(0f, -20f, 0f);
            var renderer = stream.GetComponent<Renderer>();
            if (renderer != null && renderer.sharedMaterial != null)
            {
                var mat = new Material(renderer.sharedMaterial) { color = new Color(0.25f, 0.45f, 0.7f) };
                renderer.sharedMaterial = mat;
            }
        }

        static void BuildVillagers()
        {
            // 11 villagers around camp; positions fan out inside/near the fire.
            for (int i = 0; i < 11; i++)
            {
                float angle = i / 11f * Mathf.PI * 2f;
                float ringRadius = 3f + (i % 3);
                var pos = CampCenter + new Vector3(
                    Mathf.Cos(angle) * ringRadius, 0f, Mathf.Sin(angle) * ringRadius);
                CreateVillager($"Villager_{i:D2}", pos, seed: i);
            }

            // The 12th villager works the far forest edge: the dusk drama beat.
            CreateVillager("Villager_FarNW", FarVillagerPost, seed: 11);
        }

        static void CreateVillager(string name, Vector3 groundPos, int seed)
        {
            var go = GameObject.CreatePrimitive(PrimitiveType.Capsule);
            go.name = name;
            go.transform.position = groundPos + new Vector3(0f, 1f, 0f);
            go.transform.localScale = new Vector3(0.6f, 0.9f, 0.6f);
            var agent = go.AddComponent<VillagerAgent>();
            agent.seed = seed;
        }

        static void BuildWorkAssignments()
        {
            var go = new GameObject("VillagerWorkAssigner");
            var assigner = go.AddComponent<VillagerWorkAssigner>();
            assigner.storagePoint = new Vector3(3f, 0f, 3f); // the storage pile
            assigner.taskSites = new[]
            {
                BeachCenter + new Vector3(3f, 0f, 1f),   // wreck salvage
                BeachCenter + new Vector3(1f, 0f, 4f),   // wreck salvage
                new Vector3(-4f, 0f, 2f),                // camp build zone (shelter A)
                new Vector3(-2f, 0f, 5f),                // camp build zone (shelter B)
                new Vector3(6f, 0f, -3f),                // camp build zone (open)
                ForestEdgeCenter + new Vector3(0f, 0f, 2f), // forest edge: the risky one
            };
        }

        // ------------------------------------------------------------------
        // Generated-asset helper
        // ------------------------------------------------------------------

        /// <summary>
        /// Instantiates the imported GLB for <paramref name="assetId"/> when it
        /// exists, otherwise a primitive stand-in. GLB pivots are center-bottom
        /// (ART_BIBLE.md) so they sit directly on <paramref name="groundPos"/>;
        /// primitives are lifted by <paramref name="primitiveYOffset"/> because
        /// Unity primitives pivot at their center. Never throws.
        /// </summary>
        static GameObject InstantiateGenerated(
            string assetId, Vector3 groundPos, string name,
            PrimitiveType fallback, Vector3 fallbackScale, float primitiveYOffset)
        {
            try
            {
                string assetPath = $"{GeneratedAssetFolder}/{assetId}.glb";
                var prefab = AssetDatabase.LoadAssetAtPath<GameObject>(assetPath);
                if (prefab != null)
                {
                    var instance = (GameObject)PrefabUtility.InstantiatePrefab(prefab);
                    if (instance != null)
                    {
                        instance.name = name;
                        instance.transform.position = groundPos;
                        return instance;
                    }
                }
            }
            catch (Exception e)
            {
                Debug.LogWarning($"[Abbey] Could not instantiate generated asset " +
                                 $"'{assetId}' ({e.Message}); using a primitive stand-in.");
            }

            var go = GameObject.CreatePrimitive(fallback);
            go.name = name;
            go.transform.position = groundPos + new Vector3(0f, primitiveYOffset, 0f);
            go.transform.localScale = fallbackScale;
            return go;
        }
    }
}
